"use strict";(self.webpackChunkwebsite_new=self.webpackChunkwebsite_new||[]).push([[8686],{60398(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"rayforge-1.2-addons-camera-ai","metadata":{"permalink":"/zh-CN/blog/rayforge-1.2-addons-camera-ai","source":"@site/blog/2026-03-10-rayforge-1.2-addons-camera-ai.md","title":"Rayforge 1.2 - AI Generator, Camera Enhancements, and Improved Add-ons","description":"Rayforge 1.2 brings an AI workpiece generator, significant camera","date":"2026-03-10T00:00:00.000Z","tags":[{"inline":true,"label":"release","permalink":"/zh-CN/blog/tags/release"},{"inline":true,"label":"1.2","permalink":"/zh-CN/blog/tags/1-2"},{"inline":true,"label":"addons","permalink":"/zh-CN/blog/tags/addons"},{"inline":true,"label":"camera","permalink":"/zh-CN/blog/tags/camera"},{"inline":true,"label":"ai","permalink":"/zh-CN/blog/tags/ai"}],"readingTime":3.36,"hasTruncateMarker":true,"authors":[{"name":"Rayforge Team","title":"Core development team","url":"https://github.com/barebaric/rayforge","imageURL":"/zh-CN/images/icon.svg","key":"rayforge_team","page":null}],"frontMatter":{"slug":"rayforge-1.2-addons-camera-ai","title":"Rayforge 1.2 - AI Generator, Camera Enhancements, and Improved Add-ons","authors":"rayforge_team","tags":["release","1.2","addons","camera","ai"]},"unlisted":false,"nextItem":{"title":"Rayforge 1.1 - MacOS Support, Pipeline Rewrite, G-code Console, and Unified Raster","permalink":"/zh-CN/blog/rayforge-1.1-pipeline-rewrite"}},"content":"Rayforge 1.2 brings an AI workpiece generator, significant camera\\nenhancements, and a completely revamped add-on system with core\\nfunctionality now available as optional modules.\\n\\n\x3c!-- truncate --\x3e\\n\\n## AI Workpiece Generator Add-on\\n\\nA new experimental add-on allows generating workpieces from text prompts.\\nThis is great for quickly creating simple designs or getting inspiration\\nfor new projects.\\n\\nThis is a first step, and we\'re excited about the possibilities this\\nopens up for the future!\\n\\n## Camera Enhancements\\n\\nThanks to the incredible work of **MausRundung**, the camera system has\\nreceived a major overhaul:\\n\\n### Image Enhancement\\n\\n- Temporal noise reduction with configurable strength\\n- Cleaner preview images, especially in low-light conditions\\n\\n### Fisheye Distortion Correction\\n\\n- Radial distortion correction (k1, k2 parameters)\\n- Tangential distortion correction (p1, p2 parameters)\\n- Perfect for wide-angle lenses\\n\\n### Improved Alignment UI\\n\\n- Zoom, pan, and keyboard navigation in the alignment dialog\\n- Better point dragging with visual feedback\\n- Image stretching and positioning controls with offsets\\n\\n## Improved Add-on System\\n\\nThe add-on system has been greatly improved. The main change is that much\\nof the core functionality has been moved into add-ons that are installed\\nby default, but can be disabled or enabled as needed:\\n\\n**Core as Add-ons**\\nThe built-in transformers and laser essentials have been converted to\\nadd-ons. This makes Rayforge more modular - you can disable features you\\ndon\'t need or enable only what you want.\\n\\n**Add-on Capabilities**\\nAdd-ons can now:\\n- Register transformers (post-processors) for custom G-code manipulation\\n- Register keyboard shortcuts for custom workflows\\n- Hook into the backend and frontend independently\\n\\n**Commercial Support**\\nThe system now supports paid and third-party add-ons, enabling developers\\nto create commercial extensions for Rayforge.\\n\\n## Stock Improvements\\n\\nStock handling is now more flexible:\\n\\n- **Document-level stock** - stock is no longer tied to individual layers\\n- **Duplicate stock** using Ctrl+D\\n- **Non-rectangular stock** - convert any workpiece to stock for irregular\\n  materials\\n\\n## Sketcher Improvements\\n\\nThe parametric sketcher received several quality-of-life improvements in\\nthis release:\\n\\n- **Live preview for line tool** - see the line before you commit\\n- **Dimension display** - shows dimensions while adding geometry\\n- **Snap-to-grid** - hold Ctrl to snap to the grid\\n- **Entity highlighting** - hovered entities and constraints are highlighted\\n- **Toolbar shortcuts** - shows currently available keyboard shortcuts\\n- **Connected selection** - Shift+Double click selects connected geometry\\n- **Arc radius adjustment** - change arc radius while adding the second endpoint\\n\\n## More New Features\\n\\n### Crop to Stock Post-Processor\\n\\nA new post-processor that automatically crops operations to your stock\\nboundaries, saving time and material.\\n\\n### Inter-Workpiece Path Optimization\\n\\nThe path optimizer now also optimizes the workpiece order, reducing travel\\ndistance when working with multiple workpieces in a single job. Previously,\\nRayforge only optimized travel paths within individual workpieces.\\n\\n### Configurable Cut/Raster Colors\\n\\nEach laser can now have its own cut and raster colors, making it easier\\nto distinguish between different laser heads.\\n\\n### Quick WCS Positioning\\n\\nClick anywhere on the canvas to set the work coordinate system origin.\\n\\n### OMTech K40+ Profile\\n\\nNew machine profile for the popular OMTech K40+ laser cutter.\\n\\n### Mach4 G-code Dialect\\n\\nNew built-in G-code dialect for Mach4 controllers using M67 for spindle\\nspeed (laser power) control.\\n\\n### Platform Updates\\n\\n- Updated macOS support thanks to **Pablo Gil**\\n- Flatpak updates thanks to **fllmn**\\n\\n## Bug Fixes\\n\\nThis release addresses many issues:\\n\\n- Add-on not enabled immediately after installation\\n- macOS bundle issues with GTK modules and built-in add-ons\\n- Tasker startup crash with DictProxy type annotations\\n- Old project files not showing new transformers\\n- SVG exporter stacking multiple workpieces on top of each other\\n- Auto layout for rotated stock\\n- Windows build using wrong version string on forks\\n- Mac and Windows builds not finding icon\\n\\nSee the CHANGELOG on GitHub for the complete list.\\n\\n## Special Thanks\\n\\nThis release was made possible with the support of our Patreon supporters:\\n\\n- 2 anonymous contributors\\n- Amsel\\n- froqstar\\n\\nAnd thanks to **MausRundung** for the camera enhancements, **Pablo Gil** for\\nmacOS updates, and **fllmn** for Flatpak updates!\\n\\n## Download Rayforge 1.2\\n\\n- [GitHub Releases](https://github.com/barebaric/rayforge/releases)\\n- [Website](https://rayforge.org/)\\n\\n## Join the Community\\n\\n- [Discord](https://discord.gg/sTHNdTtpQJ)\\n- [Patreon](https://www.patreon.com/c/knipknap)"},{"id":"rayforge-1.1-pipeline-rewrite","metadata":{"permalink":"/zh-CN/blog/rayforge-1.1-pipeline-rewrite","source":"@site/blog/2026-02-27-rayforge-1.1-pipeline-rewrite.md","title":"Rayforge 1.1 - MacOS Support, Pipeline Rewrite, G-code Console, and Unified Raster","description":"Rayforge 1.1","date":"2026-02-27T00:00:00.000Z","tags":[{"inline":true,"label":"release","permalink":"/zh-CN/blog/tags/release"},{"inline":true,"label":"1.1","permalink":"/zh-CN/blog/tags/1-1"},{"inline":true,"label":"pipeline","permalink":"/zh-CN/blog/tags/pipeline"},{"inline":true,"label":"raster","permalink":"/zh-CN/blog/tags/raster"},{"inline":true,"label":"gcode","permalink":"/zh-CN/blog/tags/gcode"}],"readingTime":2.48,"hasTruncateMarker":true,"authors":[{"name":"Rayforge Team","title":"Core development team","url":"https://github.com/barebaric/rayforge","imageURL":"/zh-CN/images/icon.svg","key":"rayforge_team","page":null}],"frontMatter":{"slug":"rayforge-1.1-pipeline-rewrite","title":"Rayforge 1.1 - MacOS Support, Pipeline Rewrite, G-code Console, and Unified Raster","authors":"rayforge_team","tags":["release","1.1","pipeline","raster","gcode"]},"unlisted":false,"prevItem":{"title":"Rayforge 1.2 - AI Generator, Camera Enhancements, and Improved Add-ons","permalink":"/zh-CN/blog/rayforge-1.2-addons-camera-ai"},"nextItem":{"title":"Rayforge 1.0 - \u5468\u5c81\u5e86\u5178","permalink":"/zh-CN/blog/rayforge-1.0-first-birthday"}},"content":"![Rayforge 1.1](/images/rayforge-1.1.png)\\n\\nRayforge 1.1 brings a powerful new G-code console, unified raster operations,\\nand a completely rebuilt data pipeline for improved performance and stability.\\n\\n\x3c!-- truncate --\x3e\\n\\n## MacOS Support\\n\\nThanks to the incredible work of GitHub user **pgilfernandez**, Rayforge\\nnow officially supports macOS! Both Intel and Apple Silicon Macs are\\nsupported. This has been a long-requested feature, and we\'re thrilled to\\nwelcome Mac users to the Rayforge community.\\n\\n## The Big Story: Complete Pipeline Rewrite\\n\\nThe headline feature of this release is a complete rewrite of the data\\npipeline backend. The new architecture is based on a Directed Acyclic Graph\\n(DAG), which brings significant improvements:\\n\\n- **Better performance** for complex projects with many operations\\n- **Reduced memory usage** through more efficient data handling\\n- **Smoother UI responsiveness** during heavy processing\\n- **Fixed memory leaks** that affected long editing sessions\\n\\nThis foundational upgrade makes Rayforge more robust and prepares the\\ncodebase for future features.\\n\\n## Unified Raster Operations\\n\\nThe old \\"raster\\", \\"depth\\", and \\"dither\\" operations have been merged into a\\nsingle, unified raster operation. This simplifies the workflow while giving\\nyou more control:\\n\\n- **Configurable line distance** in all raster operations\\n- **New \\"Raster (Dither)\\" operation** with configurable algorithms\\n- **Auto thresholding** for Variable Power and Multipass modes\\n- **Histogram** in the raster engraver for visual threshold setting\\n- **Symbolic visualization** of raster direction in the rasterizer\\n\\n## G-code Console\\n\\nThe log view has been replaced with a fully-featured G-code terminal. You can\\nnow send commands directly to your machine, view responses in real-time, and\\ninteract with your laser cutter more directly than ever before.\\n\\n## More New Features\\n\\n### Export Support\\n\\nYou can now export your documents or selected objects to SVG and DXF formats.\\nThis is great for sharing designs or using them in other software.\\n\\n### Sketcher Improvements\\n\\n- **Angle constraints** are now available in the parametric sketcher\\n- **Conflicting constraints** are highlighted in red for easier debugging\\n\\n### Machine Configuration\\n\\n- Axis extents, work surface, and soft limits can now be configured per machine\\n- Built-in G-code dialect supporting dynamic power mode\\n\\n### Other Additions\\n\\n- Increased maximum laser spot size to 10 mm\\n- `RAYFORGE_MAX_WORKERS` environment variable to limit processes\\n- macOS packaging scripts and resources for better platform support\\n- `--uiscript` CLI argument for executing scripts after the UI is up\\n\\n## Bug Fixes\\n\\nThis release addresses many issues:\\n\\n- Multiple memory leaks in the data pipeline\\n- Race conditions between worker pool task completion and pipeline shutdown\\n- Camera device scanning crash on Windows\\n- Multipass post-processor exception\\n- Rasterizer angle causing distortion\\n- Various macOS issues: shm_open length errors, SVG rendering fallback,\\n  keyboard shortcuts\\n- Workpiece stage not emitting correct node state\\n- Zoom resolution stuck until resizing at least once\\n- Blurry view overlay on startup\\n- Unresponsive serial ports now handled gracefully\\n\\n## Special Thanks\\n\\nThis release was made possible with the support of our Patreon supporters:\\n\\n- 2 anonymous contributors\\n- Amsel\\n\\nThank you for supporting Rayforge development!\\n\\n## Download Rayforge 1.1\\n\\n- [GitHub Releases](https://github.com/barebaric/rayforge/releases)\\n- [Website](https://rayforge.org/)\\n\\n## Join the Community\\n\\n- [Discord](https://discord.gg/sTHNdTtpQJ)\\n- [Patreon](https://www.patreon.com/c/knipknap)"},{"id":"rayforge-1.0-first-birthday","metadata":{"permalink":"/zh-CN/blog/rayforge-1.0-first-birthday","source":"@site/i18n/zh-CN/docusaurus-plugin-content-blog/2026-01-29-rayforge-1.0-first-birthday.md","title":"Rayforge 1.0 - \u5468\u5c81\u5e86\u5178","description":"Rayforge 1.0","date":"2026-01-29T00:00:00.000Z","tags":[{"inline":true,"label":"release","permalink":"/zh-CN/blog/tags/release"},{"inline":true,"label":"1","permalink":"/zh-CN/blog/tags/1"},{"inline":true,"label":"milestone","permalink":"/zh-CN/blog/tags/milestone"}],"readingTime":3.56,"hasTruncateMarker":true,"authors":[{"name":"Rayforge Team","title":"Core development team","url":"https://github.com/barebaric/rayforge","imageURL":"/zh-CN/images/icon.svg","key":"rayforge_team","page":null}],"frontMatter":{"slug":"rayforge-1.0-first-birthday","title":"Rayforge 1.0 - \u5468\u5c81\u5e86\u5178","authors":"rayforge_team","tags":["release","1","milestone"]},"unlisted":false,"prevItem":{"title":"Rayforge 1.1 - MacOS Support, Pipeline Rewrite, G-code Console, and Unified Raster","permalink":"/zh-CN/blog/rayforge-1.1-pipeline-rewrite"},"nextItem":{"title":"\u4f7f\u7528 Rayforge \u83b7\u5f97\u66f4\u597d\u6fc0\u5149\u96d5\u523b\u6548\u679c\u7684 5 \u4e2a\u6280\u5de7","permalink":"/zh-CN/blog/5-tips-better-engraving"}},"content":"![Rayforge 1.0](/images/rayforge-1.0.png)\\n\\n\u4eca\u5929\u6807\u5fd7\u7740 Rayforge \u7684\u4e00\u4e2a\u7279\u6b8a\u91cc\u7a0b\u7891\u2014\u2014\u6211\u4eec\u5728\u9879\u76ee\u7684\u4e00\u5468\u5c81\u751f\u65e5\u5f53\u5929\u53d1\u5e03 1.0 \u7248\u672c\uff01\u4ece 2025 \u5e74 2 \u6708 1 \u65e5\u7684\u7b2c\u4e00\u6b21\u63d0\u4ea4\u5f00\u59cb\uff0c\u8fd9\u5df2\u7ecf\u53d1\u5c55\u6210\u4e3a\u4e00\u4e2a\u529f\u80fd\u9f50\u5168\u7684\u6fc0\u5149\u5207\u5272\u548c\u96d5\u523b\u5e73\u53f0\u3002\\n\\n\x3c!-- truncate --\x3e\\n\\n## \u8fc4\u4eca\u4e3a\u6b62\u7684\u65c5\u7a0b\\n\\n\u5728\u8fc7\u53bb\u7684\u4e00\u5e74\u91cc\uff0cRayforge \u5df2\u4ece\u4e00\u4e2a\u57fa\u672c\u7684\u6fc0\u5149\u63a7\u5236\u5de5\u5177\u6f14\u53d8\u4e3a\u4e00\u4e2a\u7efc\u5408\u6027\u7684\u8bbe\u8ba1\u548c\u5236\u9020\u5e73\u53f0\u3002\u6211\u4eec\u4ece\u96f6\u5f00\u59cb\u6784\u5efa\u4e86\u4e00\u5207\uff1a\u53c2\u6570\u5316 2D CAD \u7cfb\u7edf\u30013D G-code \u9884\u89c8\u3001\u591a\u56fe\u5c42\u652f\u6301\u3001\u591a\u6fc0\u5149\u652f\u6301\u3001\u76f8\u673a\u5bf9\u9f50\u3001\u5de5\u4f5c\u5750\u6807\u7cfb\u7b49\u7b49\u3002\\n\\n\u6b64\u6b21\u53d1\u5e03\u4ee3\u8868\u4e86\u8fd9\u4e00\u613f\u666f\u7684\u9876\u70b9\u2014\u2014\u4e00\u4e2a\u7a33\u5b9a\u3001\u53ef\u7528\u4e8e\u751f\u4ea7\u7684\u5de5\u5177\uff0c\u80fd\u591f\u5904\u7406\u73b0\u5b9e\u4e16\u754c\u7684\u6fc0\u5149\u5207\u5272\u548c\u96d5\u523b\u5de5\u4f5c\u6d41\u7a0b\u3002\\n\\n## 1.0 \u7248\u672c\u7684\u65b0\u529f\u80fd\\n\\n### \u9879\u76ee\u4fdd\u5b58/\u52a0\u8f7d\\n\\n\u6700\u53d7\u8bf7\u6c42\u7684\u529f\u80fd\u7ec8\u4e8e\u6765\u4e86\u3002\u60a8\u73b0\u5728\u53ef\u4ee5\u4fdd\u5b58\u5b8c\u6574\u7684\u5de5\u4f5c\u6d41\u7a0b\u5e76\u5728\u4ee5\u540e\u6062\u590d\u3002`.ryp`\uff08\u9879\u76ee\uff09\u548c `.rfs`\uff08\u8349\u56fe\uff09\u6587\u4ef6\u6269\u5c55\u540d\u5df2\u5728\u7cfb\u7edf\u8303\u56f4\u5185\u6ce8\u518c\uff0c\u56e0\u6b64\u60a8\u53ef\u4ee5\u53cc\u51fb\u9879\u76ee\u76f4\u63a5\u6253\u5f00\u5b83\u4eec\u3002\u6700\u8fd1\u6587\u4ef6\u83dc\u5355\u53ef\u8ba9\u60a8\u5feb\u901f\u8bbf\u95ee\u60a8\u7684\u5de5\u4f5c\u3002\\n\\n### \u5e26\u6587\u672c\u652f\u6301\u7684\u53c2\u6570\u5316\u8349\u56fe\u5668\\n\\n\u8349\u56fe\u5668\u73b0\u5728\u652f\u6301\u5177\u6709\u5b8c\u6574\u7ea6\u675f\u96c6\u6210\u7684\u6587\u672c\u3002\u5728\u8349\u56fe\u4e2d\u6dfb\u52a0\u6587\u672c\u3001\u5e94\u7528\u7eb5\u6a2a\u6bd4\u7ea6\u675f\uff0c\u5e76\u901a\u8fc7\u53c2\u6570\u63a7\u5236\u4f4d\u7f6e\u548c\u5927\u5c0f\u3002\u8fd9\u4e3a\u6fc0\u5149\u96d5\u523b\u6807\u724c\u3001\u6807\u7b7e\u548c\u88c5\u9970\u5143\u7d20\u5f00\u8f9f\u4e86\u4e00\u4e2a\u5168\u65b0\u7684\u8bbe\u8ba1\u53ef\u80fd\u6027\u4e16\u754c\u3002\\n\\n### \u7edf\u4e00\u5e95\u90e8\u9762\u677f\\n\\n\u70b9\u52a8\u5bf9\u8bdd\u6846\u548c\u65e5\u5fd7\u89c6\u56fe\u5df2\u5408\u5e76\u4e3a\u4e00\u4e2a\u7edf\u4e00\u7684\u5e95\u90e8\u9762\u677f\u3002\u8fd9\u79cd\u6574\u5408\u63d0\u4f9b\u4e86\u66f4\u7b80\u6d01\u7684\u5de5\u4f5c\u7a7a\u95f4\uff0c\u540c\u65f6\u4fdd\u6301\u57fa\u672c\u7684\u673a\u5668\u63a7\u5236\u548c\u76d1\u63a7\u5de5\u5177\u6613\u4e8e\u8bbf\u95ee\u3002\u8be5\u9762\u677f\u5177\u6709\u6807\u7b7e\u5f0f\u8bbf\u95ee\u70b9\u52a8\u63a7\u5236\u548c\u65e5\u5fd7\u8f93\u51fa\u7684\u529f\u80fd\uff0c\u4f7f\u5207\u6362\u64cd\u4f5c\u53d8\u5f97\u5bb9\u6613\uff0c\u800c\u4e0d\u4f1a\u635f\u5931\u5c4f\u5e55\u7a7a\u95f4\u3002\\n\\n### \u5176\u4ed6\u6539\u8fdb\\n\\n- **\u5e95\u90e8\u9762\u677f**\uff1a\u70b9\u52a8\u5bf9\u8bdd\u6846\u548c\u65e5\u5fd7\u89c6\u56fe\u73b0\u5728\u5408\u5e76\u4e3a\u7edf\u4e00\u7684\u5e95\u90e8\u9762\u677f\\n- **\u5bfc\u5165\u5bf9\u8bdd\u6846**\uff1a\u9519\u8bef\u73b0\u5728\u88ab\u6536\u96c6\u5e76\u4e00\u8d77\u663e\u793a\\n- **\u5bfc\u5165\u5668**\uff1a\u51e0\u4e4e\u5b8c\u5168\u91cd\u5199\u4ee5\u63d0\u9ad8\u53ef\u6d4b\u8bd5\u6027\\n- **\u8349\u56fe\u5668\u7a33\u5b9a\u6027**\uff1a\u6c42\u89e3\u5668\u73b0\u5728\u504f\u5411\u70b9\u4ee5\u5b9e\u73b0\u66f4\u7a33\u5b9a\u7684\u62d6\u52a8\\n- **\u9519\u8bef\u4fee\u590d**\uff1a\u591a\u56fe\u5c42 DXF \u5bfc\u5165\u3001\u5bf9\u9f50\u9519\u8bef\u3001\u5c45\u4e2d\u95ee\u9898\u7b49\\n\\n## \u529f\u80fd\u4eae\u70b9\\n\\nRayforge 1.0 \u5305\u542b\u8d85\u8fc7 60 \u9879\u529f\u80fd\uff1a\\n\\n**\u8bbe\u8ba1\u5de5\u5177**\\n\\n- \u5e26\u53c2\u6570\u5316\u8349\u56fe\u7684 2D CAD\\n- \u51e0\u4f55\u548c\u5c3a\u5bf8\u7ea6\u675f\\n- \u8349\u56fe\u4e2d\u7684\u6587\u672c\u652f\u6301\\n- \u591a\u56fe\u5c42\u652f\u6301\\n\\n**\u5236\u9020**\\n\\n- 2.5D \u64cd\u4f5c\uff08\u8f6e\u5ed3\u3001\u5149\u6805\u3001\u6df1\u5ea6\u96d5\u523b\uff09\\n- \u591a\u6fc0\u5149\u652f\u6301\\n- \u5de5\u4f5c\u5750\u6807\u7cfb\uff08G54-G59\uff09\\n- \u8def\u5f84\u4f18\u5316\u548c\u5e73\u6ed1\\n- \u5e26\u81ea\u52a8\u653e\u7f6e\u7684\u56fa\u5b9a\u6807\u7b7e\\n\\n**\u5bfc\u5165/\u5bfc\u51fa**\\n\\n- \u652f\u6301 SVG\u3001DXF\u3001PDF\u3001JPEG\u3001PNG\u3001BMP\u3001Ruida \u6587\u4ef6\\n- \u5177\u6709\u591a\u79cd\u7b97\u6cd5\u7684\u77e2\u91cf\u63cf\u6479\\n- \u56fe\u50cf\u9884\u5904\u7406\uff08\u53bb\u566a\u3001\u53cd\u8f6c\u3001\u9608\u503c\uff09\\n\\n**\u673a\u5668\u63a7\u5236**\\n\\n- \u591a\u673a\u5668\u914d\u7f6e\u6587\u4ef6\\n- GRBL\u3001Smoothieware\u3001Marlin \u7684\u56fa\u4ef6\u8bbe\u7f6e\\n- G-code \u5b8f\u548c\u94a9\u5b50\\n- \u53d8\u91cf\u66ff\u6362\\n- \u5e26\u5b9e\u65f6\u72b6\u6001\u7684\u7ec8\u7aef\u63a7\u5236\u53f0\\n\\n**\u53ef\u89c6\u5316**\\n\\n- \u5177\u6709\u5b8c\u6574\u6a21\u62df\u7684 3D G-code \u9884\u89c8\\n- \u76f8\u673a\u5bf9\u9f50\\n- \u6df1\u8272\u548c\u6d45\u8272\u4e3b\u9898\\n- \u591a\u8bed\u8a00\u652f\u6301\\n\\n## \u56de\u987e\\n\\n\u7b2c\u4e00\u6b21\u63d0\u4ea4\u662f\u5728 2025 \u5e74 2 \u6708 1 \u65e5 19:37:27 \u8fdb\u884c\u7684\u3002\u8fd9\u662f\u4e00\u4e2a\u7b80\u5355\u7684\\"\u521d\u59cb\u5bfc\u5165\\"\uff0c\u5177\u6709\u57fa\u672c\u7684 SVG \u6e32\u67d3\u652f\u6301\u3002\u4ece\u90a3\u65f6\u8d77\uff0c\u6211\u4eec\uff1a\\n\\n- \u53d1\u5e03\u4e86 28 \u4e2a\u7248\u672c\uff080.13 \u5230 0.28\uff0c\u52a0\u4e0a 1.0\uff09\\n- \u6dfb\u52a0\u4e86\u8d85\u8fc7 60 \u9879\u529f\u80fd\\n- \u4fee\u590d\u4e86\u6570\u767e\u4e2a\u9519\u8bef\\n- \u5efa\u7acb\u4e86\u7528\u6237\u548c\u8d21\u732e\u8005\u793e\u533a\\n- \u4e3a Windows\u3001Linux\uff08deb\u3001snap\u3001flatpak\uff09\u548c macOS \u521b\u5efa\u4e86\u5b89\u88c5\u7a0b\u5e8f\\n\\n## \u63a5\u4e0b\u6765\u662f\u4ec0\u4e48\uff1f\\n\\n1.0 \u7248\u672c\u662f\u4e00\u4e2a\u91cc\u7a0b\u7891\uff0c\u800c\u4e0d\u662f\u7ec8\u70b9\u3002\u672a\u6765\u7684\u8def\u7ebf\u56fe\u5305\u62ec\uff1a\\n\\n- \u589e\u5f3a\u7684\u77e2\u91cf\u5de5\u5177\u548c\u7f16\u8f91\u529f\u80fd\\n- \u66f4\u5e7f\u6cdb\u7684\u786c\u4ef6\u652f\u6301\\n- \u5927\u578b\u9879\u76ee\u7684\u6027\u80fd\u4f18\u5316\\n- \u66f4\u591a\u673a\u5668\u914d\u7f6e\u6587\u4ef6\u548c\u65b9\u8a00\\n- \u793e\u533a\u9a71\u52a8\u7684\u5305\u751f\u6001\u7cfb\u7edf\\n\\n## \u4e0b\u8f7d Rayforge 1.0\\n\\n\u4ece\u6211\u4eec\u7684\u7f51\u7ad9\u83b7\u53d6\u6700\u65b0\u7248\u672c\uff1ahttps://rayforge.org/\\n\\n\u9002\u7528\u4e8e\u4ee5\u4e0b\u5e73\u53f0\u7684\u5b89\u88c5\u7a0b\u5e8f\uff1a\\n\\n- Windows\uff08\u5b89\u88c5\u7a0b\u5e8f\uff09\\n- Linux\uff08deb\u3001snap\u3001flatpak\uff09\\n- macOS\uff08dmg\uff09\\n\\n## \u52a0\u5165\u793e\u533a\\n\\n- **GitHub**: https://github.com/barebaric/rayforge\\n- **Discord**: https://discord.gg/sTHNdTtpQJ\\n- **Patreon**: https://www.patreon.com/c/knipknap\\n\\n\u611f\u8c22\u6240\u6709\u5728\u8fc7\u53bb\u4e00\u5e74\u4e2d\u8d21\u732e\u3001\u6d4b\u8bd5\u3001\u62a5\u544a\u9519\u8bef\u6216\u4f7f\u7528 Rayforge \u7684\u4eba\u3002\u4e3a\u6784\u5efa\u5f00\u6e90\u5236\u9020\u672a\u6765\u7684\u53c8\u4e00\u5e74\u5e72\u676f\uff01\\n\\n---\\n\\n*Rayforge \u4e00\u5468\u5c81\u751f\u65e5\u5feb\u4e50\uff01\ud83c\udf82*"},{"id":"5-tips-better-engraving","metadata":{"permalink":"/zh-CN/blog/5-tips-better-engraving","source":"@site/i18n/zh-CN/docusaurus-plugin-content-blog/2025-02-20-5-tips-better-engraving.md","title":"\u4f7f\u7528 Rayforge \u83b7\u5f97\u66f4\u597d\u6fc0\u5149\u96d5\u523b\u6548\u679c\u7684 5 \u4e2a\u6280\u5de7","description":"3D \u9884\u89c8","date":"2025-02-20T00:00:00.000Z","tags":[{"inline":true,"label":"engraving","permalink":"/zh-CN/blog/tags/engraving"},{"inline":true,"label":"optimization","permalink":"/zh-CN/blog/tags/optimization"},{"inline":true,"label":"quality","permalink":"/zh-CN/blog/tags/quality"},{"inline":true,"label":"workflow","permalink":"/zh-CN/blog/tags/workflow"}],"readingTime":3.62,"hasTruncateMarker":true,"authors":[{"name":"Rayforge Team","title":"Core development team","url":"https://github.com/barebaric/rayforge","imageURL":"/zh-CN/images/icon.svg","key":"rayforge_team","page":null}],"frontMatter":{"slug":"5-tips-better-engraving","title":"\u4f7f\u7528 Rayforge \u83b7\u5f97\u66f4\u597d\u6fc0\u5149\u96d5\u523b\u6548\u679c\u7684 5 \u4e2a\u6280\u5de7","authors":"rayforge_team","tags":["engraving","optimization","quality","workflow"]},"unlisted":false,"prevItem":{"title":"Rayforge 1.0 - \u5468\u5c81\u5e86\u5178","permalink":"/zh-CN/blog/rayforge-1.0-first-birthday"},"nextItem":{"title":"\u591a\u6fc0\u5149\u652f\u6301 - \u4e3a\u6bcf\u4e2a\u64cd\u4f5c\u9009\u62e9\u4e0d\u540c\u7684\u6fc0\u5149\u5668","permalink":"/zh-CN/blog/multi-laser-support"}},"content":"![3D \u9884\u89c8](/screenshots/main-3d.png)\\n\\n\u83b7\u5f97\u4e13\u4e1a\u54c1\u8d28\u7684\u6fc0\u5149\u96d5\u523b\u6548\u679c\u4e0d\u4ec5\u9700\u8981\u597d\u7684\u786c\u4ef6\u2014\u2014\u60a8\u7684\u8f6f\u4ef6\u8bbe\u7f6e\u548c\u5de5\u4f5c\u6d41\u7a0b\u4e5f\u5f88\u91cd\u8981\u3002\u4ee5\u4e0b\u662f\u5e2e\u52a9\u60a8\u5145\u5206\u5229\u7528 Rayforge \u7684\u4e94\u4e2a\u6280\u5de7\u3002\\n\\n\x3c!-- truncate --\x3e\\n\\n## 1. \u4f7f\u7528\u8fc7\u626b\u63cf\u83b7\u5f97\u66f4\u5e73\u6ed1\u7684\u5149\u6805\u96d5\u523b\\n\\n\u5728\u8fdb\u884c\u5149\u6805\u96d5\u523b\u65f6\uff0c\u4e00\u4e2a\u5e38\u89c1\u95ee\u9898\u662f\u5728\u6fc0\u5149\u6539\u53d8\u65b9\u5411\u7684\u8fb9\u7f18\u5904\u51fa\u73b0\u53ef\u89c1\u7684\u7ebf\u6761\u6216\u4e0d\u4e00\u81f4\u3002\u8fd9\u662f\u56e0\u4e3a\u6fc0\u5149\u5934\u9700\u8981\u51cf\u901f\u548c\u52a0\u901f\uff0c\u8fd9\u4f1a\u5f71\u54cd\u96d5\u523b\u8d28\u91cf\u3002\\n\\n**\u89e3\u51b3\u65b9\u6848**\uff1a\u5728\u5149\u6805\u64cd\u4f5c\u8bbe\u7f6e\u4e2d\u542f\u7528 **\u8fc7\u626b\u63cf**\u3002\\n\\n\u8fc7\u626b\u63cf\u5c06\u6fc0\u5149\u7684\u79fb\u52a8\u8def\u5f84\u5ef6\u4f38\u5230\u5b9e\u9645\u96d5\u523b\u533a\u57df\u4e4b\u5916\uff0c\u4f7f\u6fc0\u5149\u5934\u5728\u8fdb\u5165\u5de5\u4f5c\u533a\u57df\u4e4b\u524d\u8fbe\u5230\u5168\u901f\uff0c\u5e76\u59cb\u7ec8\u4fdd\u6301\u8be5\u901f\u5ea6\u3002\u8fd9\u6837\u53ef\u4ee5\u83b7\u5f97\u66f4\u5e73\u6ed1\u3001\u66f4\u4e00\u81f4\u7684\u96d5\u523b\u6548\u679c\u3002\\n\\n\u8981\u542f\u7528\u8fc7\u626b\u63cf\uff1a\\n\\n1. \u9009\u62e9\u60a8\u7684\u5149\u6805\u64cd\u4f5c\\n2. \u6253\u5f00\u64cd\u4f5c\u8bbe\u7f6e\\n3. \u542f\u7528\\"\u8fc7\u626b\u63cf\\"\u5e76\u8bbe\u7f6e\u8ddd\u79bb\uff08\u901a\u5e38 3-5mm \u6548\u679c\u826f\u597d\uff09\\n\\n\u5728\u6211\u4eec\u7684[\u8fc7\u626b\u63cf\u6307\u5357](/docs/features/overscan)\u4e2d\u4e86\u89e3\u66f4\u591a\u4fe1\u606f\u3002\\n\\n## 2. \u901a\u8fc7\u8def\u5f84\u6392\u5e8f\u4f18\u5316\u79fb\u52a8\u65f6\u95f4\\n\\n\u5bf9\u4e8e\u5177\u6709\u8bb8\u591a\u72ec\u7acb\u8def\u5f84\u7684\u8f6e\u5ed3\u64cd\u4f5c\uff0c\u6fc0\u5149\u8bbf\u95ee\u6bcf\u4e2a\u5f62\u72b6\u7684\u987a\u5e8f\u4f1a\u663e\u8457\u5f71\u54cd\u603b\u4f5c\u4e1a\u65f6\u95f4\u3002\\n\\n**\u89e3\u51b3\u65b9\u6848**\uff1a\u4f7f\u7528 Rayforge \u5185\u7f6e\u7684 **\u79fb\u52a8\u65f6\u95f4\u4f18\u5316**\u3002\\n\\nRayforge \u53ef\u4ee5\u81ea\u52a8\u91cd\u65b0\u6392\u5e8f\u8def\u5f84\uff0c\u4ee5\u6700\u5927\u9650\u5ea6\u5730\u51cf\u5c11\u975e\u5207\u5272\u79fb\u52a8\u65f6\u95f4\u3002\u8fd9\u5bf9\u4e8e\u5177\u6709\u8bb8\u591a\u5c0f\u5bf9\u8c61\u6216\u591a\u4e2a\u5b57\u6bcd\u7684\u6587\u672c\u7684\u4f5c\u4e1a\u7279\u522b\u6709\u7528\u3002\\n\\n\u8def\u5f84\u4f18\u5316\u901a\u5e38\u9ed8\u8ba4\u542f\u7528\uff0c\u4f46\u60a8\u53ef\u4ee5\u5728\u8f6e\u5ed3\u64cd\u4f5c\u8bbe\u7f6e\u4e2d\u9a8c\u8bc1\u548c\u8c03\u6574\u5b83\u3002\\n\\n## 3. \u6dfb\u52a0\u56fa\u5b9a\u6807\u7b7e\u9632\u6b62\u96f6\u4ef6\u79fb\u52a8\\n\\n\u6ca1\u6709\u4ec0\u4e48\u6bd4\u51e0\u4e4e\u5b8c\u6210\u7684\u5207\u5272\u4f5c\u4e1a\u5728\u6700\u540e\u4e00\u523b\u56e0\u4e3a\u96f6\u4ef6\u79fb\u52a8\u6216\u4ece\u673a\u5e8a\u5e8a\u8eab\u4e0a\u6389\u843d\u800c\u6bc1\u6389\u66f4\u4ee4\u4eba\u6cae\u4e27\u7684\u4e86\u3002\\n\\n**\u89e3\u51b3\u65b9\u6848**\uff1a\u4f7f\u7528 **\u56fa\u5b9a\u6807\u7b7e** \u5c06\u96f6\u4ef6\u4fdd\u6301\u5728\u539f\u4f4d\uff0c\u76f4\u5230\u4f5c\u4e1a\u5b8c\u6210\u3002\\n\\n\u56fa\u5b9a\u6807\u7b7e\u662f\u4fdd\u6301\u96f6\u4ef6\u4e0e\u5468\u56f4\u6750\u6599\u8fde\u63a5\u7684\u5c0f\u578b\u672a\u5207\u5272\u90e8\u5206\u3002\u4f5c\u4e1a\u5b8c\u6210\u540e\uff0c\u60a8\u53ef\u4ee5\u8f7b\u677e\u53d6\u51fa\u96f6\u4ef6\uff0c\u5e76\u7528\u5200\u6216\u7802\u7eb8\u6e05\u7406\u6807\u7b7e\u3002\\n\\nRayforge \u652f\u6301\u624b\u52a8\u548c\u81ea\u52a8\u6807\u7b7e\u653e\u7f6e\uff1a\\n\\n- **\u624b\u52a8**\uff1a\u5728\u753b\u5e03\u4e0a\u7cbe\u786e\u70b9\u51fb\u60a8\u60f3\u8981\u653e\u7f6e\u6807\u7b7e\u7684\u4f4d\u7f6e\\n- **\u81ea\u52a8**\uff1a\u6307\u5b9a\u6807\u7b7e\u6570\u91cf\uff0c\u8ba9 Rayforge \u5747\u5300\u5206\u5e03\u5b83\u4eec\\n\\n\u67e5\u770b[\u56fa\u5b9a\u6807\u7b7e\u6587\u6863](/docs/features/holding-tabs)\u83b7\u53d6\u5b8c\u6574\u6307\u5357\u3002\\n\\n## 4. \u5728\u8fd0\u884c\u524d\u4ee5 3D \u9884\u89c8\u60a8\u7684\u4f5c\u4e1a\\n\\nRayforge \u6700\u6709\u4ef7\u503c\u7684\u529f\u80fd\u4e4b\u4e00\u662f 3D G-code \u9884\u89c8\u3002\u8df3\u8fc7\u8fd9\u4e00\u6b65\u76f4\u63a5\u5c06\u4f5c\u4e1a\u53d1\u9001\u5230\u673a\u5668\u5f88\u8bf1\u4eba\uff0c\u4f46\u82b1\u4e00\u70b9\u65f6\u95f4\u9884\u89c8\u53ef\u4ee5\u8282\u7701\u60a8\u7684\u65f6\u95f4\u548c\u6750\u6599\u3002\\n\\n**\u5728\u9884\u89c8\u4e2d\u8981\u6ce8\u610f\u4ec0\u4e48**\uff1a\\n\\n- \u9a8c\u8bc1\u6240\u6709\u64cd\u4f5c\u662f\u5426\u6309\u6b63\u786e\u987a\u5e8f\u6267\u884c\\n- \u68c0\u67e5\u662f\u5426\u6709\u4efb\u4f55\u610f\u5916\u7684\u5200\u5177\u8def\u5f84\u6216\u91cd\u53e0\\n- \u786e\u8ba4\u591a\u6b21\u901a\u8fc7\u64cd\u4f5c\u5177\u6709\u6b63\u786e\u7684\u901a\u8fc7\u6b21\u6570\\n- \u786e\u4fdd\u4f5c\u4e1a\u8fb9\u754c\u9002\u5408\u60a8\u7684\u6750\u6599\\n\\n\u8981\u6253\u5f00 3D \u9884\u89c8\uff0c\u5728\u751f\u6210 G-code \u540e\u70b9\u51fb\u4e3b\u5de5\u5177\u680f\u4e2d\u7684 **3D \u9884\u89c8** \u6309\u94ae\u3002\\n\\n\u5728\u6211\u4eec\u7684 [UI \u6587\u6863](/docs/ui/3d-preview)\u4e2d\u4e86\u89e3\u66f4\u591a\u5173\u4e8e 3D \u9884\u89c8\u7684\u4fe1\u606f\u3002\\n\\n## 5. \u4f7f\u7528\u81ea\u5b9a\u4e49 G-code \u94a9\u5b50\u5b9e\u73b0\u4e00\u81f4\u7684\u5de5\u4f5c\u6d41\u7a0b\\n\\n\u5982\u679c\u60a8\u53d1\u73b0\u81ea\u5df1\u5728\u6bcf\u4e2a\u4f5c\u4e1a\u524d\u540e\u90fd\u8fd0\u884c\u76f8\u540c\u7684 G-code \u547d\u4ee4\u2014\u2014\u6bd4\u5982\u5f52\u96f6\u3001\u6253\u5f00\u6c14\u8f85\u6216\u8fd0\u884c\u5bf9\u7126\u7a0b\u5e8f\u2014\u2014\u60a8\u53ef\u4ee5\u4f7f\u7528 **G-code \u5b8f\u548c\u94a9\u5b50** \u6765\u81ea\u52a8\u5316\u8fd9\u4e9b\u64cd\u4f5c\u3002\\n\\n**\u5e38\u89c1\u7528\u4f8b**\uff1a\\n\\n- **\u4f5c\u4e1a\u524d\u94a9\u5b50**\uff1a\u673a\u5668\u5f52\u96f6\u3001\u6253\u5f00\u6c14\u8f85\u3001\u8fd0\u884c\u81ea\u52a8\u5bf9\u7126\u7a0b\u5e8f\\n- **\u4f5c\u4e1a\u540e\u94a9\u5b50**\uff1a\u5173\u95ed\u6c14\u8f85\u3001\u8fd4\u56de\u539f\u70b9\u4f4d\u7f6e\u3001\u64ad\u653e\u5b8c\u6210\u63d0\u793a\u97f3\\n- **\u56fe\u5c42\u7279\u5b9a\u5b8f**\uff1a\u5728\u64cd\u4f5c\u4e4b\u95f4\u66f4\u6539\u5bf9\u7126\u9ad8\u5ea6\u3001\u5207\u6362\u6fc0\u5149\u6a21\u5757\\n\\n\u94a9\u5b50\u652f\u6301\u53d8\u91cf\u66ff\u6362\uff0c\u56e0\u6b64\u60a8\u53ef\u4ee5\u5f15\u7528\u4f5c\u4e1a\u5c5e\u6027\uff0c\u5982\u6750\u6599\u539a\u5ea6\u3001\u64cd\u4f5c\u7c7b\u578b\u7b49\u3002\\n\\n\u4f5c\u4e1a\u524d\u94a9\u5b50\u793a\u4f8b\uff1a\\n\\n```gcode\\nG28 ; Home all axes\\nM8 ; Turn on air assist\\nG0 Z{focus_height} ; Move to focus height\\n```\\n\\n\u6709\u5173\u8be6\u7ec6\u793a\u4f8b\u548c\u53d8\u91cf\u53c2\u8003\uff0c\u8bf7\u53c2\u9605\u6211\u4eec\u7684 [G-code \u5b8f\u548c\u94a9\u5b50\u6307\u5357](/docs/machine/hooks-macros)\u3002\\n\\n---\\n\\n## \u989d\u5916\u63d0\u793a\uff1a\u5148\u5728\u5e9f\u6599\u4e0a\u6d4b\u8bd5\\n\\n\u867d\u7136\u8fd9\u4e0d\u662f Rayforge \u7279\u6709\u7684\uff0c\u4f46\u503c\u5f97\u91cd\u590d\uff1a\u59cb\u7ec8\u5148\u5728\u5e9f\u6599\u4e0a\u6d4b\u8bd5\u65b0\u7684\u8bbe\u7f6e\u3001\u64cd\u4f5c\u6216\u6750\u6599\u3002\u4f7f\u7528 Rayforge \u7684\u6750\u6599\u914d\u7f6e\u6587\u4ef6\u548c\u64cd\u4f5c\u9884\u8bbe\u4fdd\u5b58\u60a8\u6d4b\u8bd5\u8fc7\u7684\u8bbe\u7f6e\u4ee5\u5907\u5c06\u6765\u4f7f\u7528\u3002\\n\\n---\\n\\n*\u6709\u60a8\u81ea\u5df1\u7684 Rayforge \u6280\u5de7\u548c\u7a8d\u95e8\uff1f\u5728 [GitHub Discussions](https://github.com/barebaric/rayforge/discussions) \u4e0a\u4e0e\u793e\u533a\u5206\u4eab\uff01*"},{"id":"multi-laser-support","metadata":{"permalink":"/zh-CN/blog/multi-laser-support","source":"@site/i18n/zh-CN/docusaurus-plugin-content-blog/2025-01-10-multi-laser-support.md","title":"\u591a\u6fc0\u5149\u652f\u6301 - \u4e3a\u6bcf\u4e2a\u64cd\u4f5c\u9009\u62e9\u4e0d\u540c\u7684\u6fc0\u5149\u5668","description":"\u76f8\u673a\u53e0\u52a0","date":"2025-01-10T00:00:00.000Z","tags":[{"inline":true,"label":"multi-laser","permalink":"/zh-CN/blog/tags/multi-laser"},{"inline":true,"label":"operations","permalink":"/zh-CN/blog/tags/operations"},{"inline":true,"label":"workflow","permalink":"/zh-CN/blog/tags/workflow"}],"readingTime":2.73,"hasTruncateMarker":true,"authors":[{"name":"Rayforge Team","title":"Core development team","url":"https://github.com/barebaric/rayforge","imageURL":"/zh-CN/images/icon.svg","key":"rayforge_team","page":null}],"frontMatter":{"slug":"multi-laser-support","title":"\u591a\u6fc0\u5149\u652f\u6301 - \u4e3a\u6bcf\u4e2a\u64cd\u4f5c\u9009\u62e9\u4e0d\u540c\u7684\u6fc0\u5149\u5668","authors":"rayforge_team","tags":["multi-laser","operations","workflow"]},"unlisted":false,"prevItem":{"title":"\u4f7f\u7528 Rayforge \u83b7\u5f97\u66f4\u597d\u6fc0\u5149\u96d5\u523b\u6548\u679c\u7684 5 \u4e2a\u6280\u5de7","permalink":"/zh-CN/blog/5-tips-better-engraving"},"nextItem":{"title":"\u6b22\u8fce\u6765\u5230 Rayforge\uff1a\u73b0\u4ee3\u6fc0\u5149\u63a7\u5236\u8f6f\u4ef6","permalink":"/zh-CN/blog/welcome-to-rayforge"}},"content":"![\u76f8\u673a\u53e0\u52a0](/images/camera-overlay.png)\\n\\nRayforge \u6700\u5f3a\u5927\u7684\u529f\u80fd\u4e4b\u4e00\u662f\u80fd\u591f\u5728\u5355\u4e2a\u4f5c\u4e1a\u4e2d\u4e3a\u4e0d\u540c\u64cd\u4f5c\u5206\u914d\u4e0d\u540c\u7684\u6fc0\u5149\u5668\u3002\u8fd9\u4e3a\u591a\u5de5\u5177\u8bbe\u7f6e\u548c\u4e13\u4e1a\u5316\u5de5\u4f5c\u6d41\u7a0b\u5f00\u542f\u4e86\u4ee4\u4eba\u5174\u594b\u7684\u53ef\u80fd\u6027\u3002\\n\\n\x3c!-- truncate --\x3e\\n\\n## \u4ec0\u4e48\u662f\u591a\u6fc0\u5149\u652f\u6301\uff1f\\n\\n\u5982\u679c\u60a8\u7684\u673a\u5668\u914d\u5907\u591a\u4e2a\u6fc0\u5149\u6a21\u5757\u2014\u2014\u4f8b\u5982\uff0c\u4e00\u4e2a\u7528\u4e8e\u96d5\u523b\u7684\u4e8c\u6781\u7ba1\u6fc0\u5149\u5668\u548c\u4e00\u4e2a\u7528\u4e8e\u5207\u5272\u7684 CO2 \u6fc0\u5149\u5668\uff0c\u6216\u8005\u9488\u5bf9\u4e0d\u540c\u6750\u6599\u4f18\u5316\u7684\u4e0d\u540c\u529f\u7387\u4e8c\u6781\u7ba1\u6fc0\u5149\u5668\u2014\u2014Rayforge \u8ba9\u60a8\u5145\u5206\u5229\u7528\u8fd9\u79cd\u8bbe\u7f6e\u3002\\n\\n\u901a\u8fc7\u591a\u6fc0\u5149\u652f\u6301\uff0c\u60a8\u53ef\u4ee5\uff1a\\n\\n- **\u4e3a\u4f5c\u4e1a\u4e2d\u7684\u4e0d\u540c\u64cd\u4f5c\u5206\u914d\u4e0d\u540c\u7684\u6fc0\u5149\u5668**\\n- **\u5728\u4f5c\u4e1a\u6267\u884c\u671f\u95f4\u81ea\u52a8\u5207\u6362\u6fc0\u5149\u6a21\u5757**\\n- **\u9488\u5bf9\u6750\u6599\u548c\u4efb\u52a1\u8fdb\u884c\u4f18\u5316**\uff0c\u4e3a\u6bcf\u4e2a\u64cd\u4f5c\u4f7f\u7528\u5408\u9002\u7684\u5de5\u5177\\n\\n## \u4f7f\u7528\u573a\u666f\\n\\n### \u6df7\u5408\u96d5\u523b\u548c\u5207\u5272\\n\\n\u60f3\u8c61\u4e00\u4e0b\u60a8\u6b63\u5728\u5236\u4f5c\u4e00\u4e2a\u6728\u5236\u6807\u724c\u9879\u76ee\uff1a\\n\\n1. **\u64cd\u4f5c 1**\uff1a\u4f7f\u7528\u4f4e\u529f\u7387\u4e8c\u6781\u7ba1\u6fc0\u5149\u5668\u96d5\u523b\u7cbe\u7ec6\u7684\u6587\u5b57\u548c\u8be6\u7ec6\u56fe\u5f62\\n2. **\u64cd\u4f5c 2**\uff1a\u5207\u6362\u5230\u66f4\u9ad8\u529f\u7387\u7684 CO2 \u6fc0\u5149\u5668\u5207\u5272\u51fa\u6807\u724c\u5f62\u72b6\\n\\n\u5728 Rayforge \u4e2d\uff0c\u60a8\u53ea\u9700\u5728\u673a\u5668\u914d\u7f6e\u6587\u4ef6\u4e2d\u5c06\u6bcf\u4e2a\u64cd\u4f5c\u5206\u914d\u7ed9\u76f8\u5e94\u7684\u6fc0\u5149\u5668\uff0c\u8f6f\u4ef6\u4f1a\u5904\u7406\u5176\u4f59\u7684\u5de5\u4f5c\u3002\\n\\n### \u6750\u6599\u7279\u5b9a\u4f18\u5316\\n\\n\u4e0d\u540c\u7c7b\u578b\u7684\u6fc0\u5149\u5668\u5728\u4e0d\u540c\u6750\u6599\u4e0a\u8868\u73b0\u51fa\u8272\uff1a\\n\\n- **\u4e8c\u6781\u7ba1\u6fc0\u5149\u5668**\uff1a\u975e\u5e38\u9002\u5408\u6728\u6750\u96d5\u523b\u3001\u76ae\u9769\u548c\u67d0\u4e9b\u5851\u6599\\n- **CO2 \u6fc0\u5149\u5668**\uff1a\u975e\u5e38\u9002\u5408\u5207\u5272\u4e9a\u514b\u529b\u3001\u6728\u6750\u548c\u5176\u4ed6\u6709\u673a\u6750\u6599\\n- **\u5149\u7ea4\u6fc0\u5149\u5668**\uff1a\u975e\u5e38\u9002\u5408\u91d1\u5c5e\u6807\u8bb0\\n\\n\u5982\u679c\u60a8\u5728\u9f99\u95e8\u7cfb\u7edf\u4e0a\u6709\u591a\u79cd\u6fc0\u5149\u7c7b\u578b\uff0cRayforge \u7684\u591a\u6fc0\u5149\u652f\u6301\u8ba9\u60a8\u53ef\u4ee5\u4e3a\u9879\u76ee\u7684\u6bcf\u4e2a\u90e8\u5206\u4f7f\u7528\u6700\u4f73\u5de5\u5177\u3002\\n\\n## \u5982\u4f55\u8bbe\u7f6e\\n\\n### 1. \u5728\u673a\u5668\u914d\u7f6e\u6587\u4ef6\u4e2d\u914d\u7f6e\u591a\u4e2a\u6fc0\u5149\u5668\\n\\n\u8f6c\u5230 **\u673a\u5668\u8bbe\u7f6e \u2192 \u591a\u6fc0\u5149\u5668** \u5e76\u5b9a\u4e49\u7cfb\u7edf\u4e2d\u7684\u6bcf\u4e2a\u6fc0\u5149\u6a21\u5757\u3002\u60a8\u53ef\u4ee5\u6307\u5b9a\uff1a\\n\\n- \u6fc0\u5149\u7c7b\u578b\u548c\u529f\u7387\u8303\u56f4\\n- \u504f\u79fb\u4f4d\u7f6e\uff08\u5982\u679c\u6fc0\u5149\u5668\u5b89\u88c5\u5728\u4e0d\u540c\u4f4d\u7f6e\uff09\\n- \u6750\u6599\u517c\u5bb9\u6027\\n\\n\u6709\u5173\u8be6\u7ec6\u8bf4\u660e\uff0c\u8bf7\u53c2\u9605\u6211\u4eec\u7684[\u6fc0\u5149\u914d\u7f6e\u6307\u5357](/docs/machine/laser)\u3002\\n\\n### 2. \u4e3a\u64cd\u4f5c\u5206\u914d\u6fc0\u5149\u5668\\n\\n\u5728\u9879\u76ee\u4e2d\u521b\u5efa\u64cd\u4f5c\u65f6\uff1a\\n\\n1. \u9009\u62e9\u64cd\u4f5c\uff08\u8f6e\u5ed3\u3001\u5149\u6805\u7b49\uff09\\n2. \u5728\u64cd\u4f5c\u8bbe\u7f6e\u4e2d\uff0c\u4ece\u4e0b\u62c9\u83dc\u5355\u4e2d\u9009\u62e9\u8981\u4f7f\u7528\u7684\u6fc0\u5149\u5668\\n3. \u914d\u7f6e\u7279\u5b9a\u4e8e\u8be5\u6fc0\u5149\u5668\u7684\u64cd\u4f5c\u53c2\u6570\\n\\n### 3. \u9884\u89c8\u5e76\u8fd0\u884c\\n\\n\u4f7f\u7528 3D \u9884\u89c8\u9a8c\u8bc1\u60a8\u7684\u5200\u5177\u8def\u5f84\uff0c\u7136\u540e\u5c06\u4f5c\u4e1a\u53d1\u9001\u5230\u673a\u5668\u3002Rayforge \u5c06\u81ea\u52a8\u751f\u6210\u9002\u5f53\u7684 G-code \u547d\u4ee4\uff0c\u6839\u636e\u9700\u8981\u5728\u6fc0\u5149\u5668\u4e4b\u95f4\u5207\u6362\u3002\\n\\n## \u6280\u672f\u7ec6\u8282\\n\\n\u5728\u5e95\u5c42\uff0cRayforge \u4f7f\u7528 G-code \u547d\u4ee4\u5728\u6fc0\u5149\u6a21\u5757\u4e4b\u95f4\u5207\u6362\u3002\u5177\u4f53\u5b9e\u73b0\u53d6\u51b3\u4e8e\u60a8\u7684\u56fa\u4ef6\u548c\u786c\u4ef6\u8bbe\u7f6e\uff0c\u4f46\u5e38\u89c1\u65b9\u6cd5\u5305\u62ec\uff1a\\n\\n- **\u5e26\u5de5\u5177\u504f\u79fb\u7684 M3/M4**\uff1a\u4f7f\u7528\u6362\u5200\u547d\u4ee4\u5728\u6fc0\u5149\u5668\u4e4b\u95f4\u5207\u6362\\n- **GPIO \u63a7\u5236**\uff1a\u4f7f\u7528\u56fa\u4ef6\u652f\u6301\u7684 GPIO \u5f15\u811a\u542f\u7528/\u7981\u7528\u4e0d\u540c\u7684\u6fc0\u5149\u6a21\u5757\\n- **\u81ea\u5b9a\u4e49\u5b8f**\uff1a\u5b9a\u4e49\u6fc0\u5149\u5207\u6362\u7684\u524d\u64cd\u4f5c\u548c\u540e\u64cd\u4f5c\u5b8f\\n\\n## \u5f00\u59cb\u4f7f\u7528\\n\\n\u591a\u6fc0\u5149\u652f\u6301\u5728 Rayforge 0.15 \u53ca\u66f4\u9ad8\u7248\u672c\u4e2d\u53ef\u7528\u3002\u5f00\u59cb\u4f7f\u7528\uff1a\\n\\n1. \u66f4\u65b0\u5230\u6700\u65b0\u7248\u672c\\n2. \u914d\u7f6e\u5177\u6709\u591a\u4e2a\u6fc0\u5149\u5668\u7684\u673a\u5668\u914d\u7f6e\u6587\u4ef6\\n3. \u5728\u6d4b\u8bd5\u9879\u76ee\u4e0a\u5c1d\u8bd5\uff01\\n\\n\u67e5\u770b[\u673a\u5668\u914d\u7f6e\u6587\u4ef6\u6587\u6863](/docs/machine/general)\u4e86\u89e3\u66f4\u591a\u8be6\u60c5\u3002\\n\\n---\\n\\n*\u6709\u591a\u6fc0\u5149\u8bbe\u7f6e\uff1f\u6211\u4eec\u5f88\u60f3\u542c\u542c\u60a8\u7684\u4f53\u9a8c\uff01\u5728 [GitHub](https://github.com/barebaric/rayforge) \u4e0a\u5206\u4eab\u60a8\u7684\u9879\u76ee\u548c\u53cd\u9988\u3002*"},{"id":"welcome-to-rayforge","metadata":{"permalink":"/zh-CN/blog/welcome-to-rayforge","source":"@site/i18n/zh-CN/docusaurus-plugin-content-blog/2024-12-15-welcome-to-rayforge.md","title":"\u6b22\u8fce\u6765\u5230 Rayforge\uff1a\u73b0\u4ee3\u6fc0\u5149\u63a7\u5236\u8f6f\u4ef6","description":"Rayforge \u4e3b\u7a97\u53e3","date":"2024-12-15T00:00:00.000Z","tags":[{"inline":true,"label":"introduction","permalink":"/zh-CN/blog/tags/introduction"},{"inline":true,"label":"features","permalink":"/zh-CN/blog/tags/features"}],"readingTime":1.96,"hasTruncateMarker":true,"authors":[{"name":"Rayforge Team","title":"Core development team","url":"https://github.com/barebaric/rayforge","imageURL":"/zh-CN/images/icon.svg","key":"rayforge_team","page":null}],"frontMatter":{"slug":"welcome-to-rayforge","title":"\u6b22\u8fce\u6765\u5230 Rayforge\uff1a\u73b0\u4ee3\u6fc0\u5149\u63a7\u5236\u8f6f\u4ef6","authors":"rayforge_team","tags":["introduction","features"]},"unlisted":false,"prevItem":{"title":"\u591a\u6fc0\u5149\u652f\u6301 - \u4e3a\u6bcf\u4e2a\u64cd\u4f5c\u9009\u62e9\u4e0d\u540c\u7684\u6fc0\u5149\u5668","permalink":"/zh-CN/blog/multi-laser-support"}},"content":"![Rayforge \u4e3b\u7a97\u53e3](/screenshots/main-standard.png)\\n\\n\u6211\u4eec\u5f88\u9ad8\u5174\u5411\u60a8\u4ecb\u7ecd Rayforge\uff0c\u8fd9\u662f\u4e00\u6b3e\u4e13\u4e3a\u57fa\u4e8e GRBL \u7684\u6fc0\u5149\u5207\u5272\u673a\u548c\u96d5\u523b\u673a\u8bbe\u8ba1\u7684\u73b0\u4ee3\u5316\u5f00\u6e90 G-code \u53d1\u9001\u5668\u548c\u63a7\u5236\u8f6f\u4ef6\u3002\\n\\n\x3c!-- truncate --\x3e\\n\\n## \u4e3a\u4ec0\u4e48\u9009\u62e9 Rayforge\uff1f\\n\\n\u5728\u6fc0\u5149\u5207\u5272\u548c\u96d5\u523b\u7684\u4e16\u754c\u4e2d\uff0c\u62e5\u6709\u53ef\u9760\u3001\u76f4\u89c2\u7684\u8f6f\u4ef6\u4e0e\u62e5\u6709\u4f18\u8d28\u786c\u4ef6\u540c\u6837\u91cd\u8981\u3002Rayforge \u4ece\u96f6\u5f00\u59cb\u6784\u5efa\uff0c\u4e13\u6ce8\u4e8e\uff1a\\n\\n- **\u73b0\u4ee3\u7528\u6237\u4f53\u9a8c**\uff1a\u57fa\u4e8e Gtk4 \u548c Libadwaita \u6784\u5efa\uff0cRayforge \u63d0\u4f9b\u7b80\u6d01\u7684\u539f\u751f\u754c\u9762\uff0c\u5728 Linux \u548c Windows \u4e0a\u90fd\u80fd\u5b8c\u7f8e\u8fd0\u884c\\n- **\u4e13\u4e1a\u529f\u80fd**\uff1a\u591a\u56fe\u5c42\u5de5\u4f5c\u6d41\u7a0b\u30013D \u9884\u89c8\u3001\u76f8\u673a\u96c6\u6210\u548c\u9ad8\u7ea7\u8def\u5f84\u751f\u6210\\n- **\u7075\u6d3b\u6027**\uff1a\u652f\u6301\u591a\u4e2a\u673a\u5668\u914d\u7f6e\u6587\u4ef6\u3001\u81ea\u5b9a\u4e49\u5b8f\u548c\u4e30\u5bcc\u7684\u914d\u7f6e\u9009\u9879\\n- **\u5f00\u653e\u5f00\u53d1**\uff1a\u793e\u533a\u9a71\u52a8\uff0c\u6b22\u8fce\u8d21\u732e\\n\\n## Rayforge \u6709\u4f55\u4e0d\u540c\uff1f\\n\\n### \u591a\u56fe\u5c42\u64cd\u4f5c\\n\\nRayforge \u7684\u7a81\u51fa\u529f\u80fd\u4e4b\u4e00\u662f\u5176\u591a\u56fe\u5c42\u5de5\u4f5c\u6d41\u7a0b\u3002\u5c06\u4e0d\u540c\u7684\u64cd\u4f5c\u5206\u914d\u7ed9\u8bbe\u8ba1\u4e2d\u7684\u4e0d\u540c\u56fe\u5c42\u2014\u2014\u5728\u4e00\u4e2a\u56fe\u5c42\u4e0a\u96d5\u523b\u7cbe\u7ec6\u7ec6\u8282\uff0c\u7136\u540e\u5728\u53e6\u4e00\u4e2a\u56fe\u5c42\u4e0a\u5207\u5272\u51fa\u4f5c\u54c1\u3002\u6240\u6709\u64cd\u4f5c\u90fd\u5728\u4e00\u4e2a\u754c\u9762\u4e2d\u65e0\u7f1d\u7ba1\u7406\u3002\\n\\n### 3D G-code \u9884\u89c8\\n\\n\u5728\u5c06\u4f5c\u4e1a\u53d1\u9001\u5230\u673a\u5668\u4e4b\u524d\uff0c\u901a\u8fc7\u6211\u4eec\u7684 3D G-code \u9884\u89c8\u7cbe\u786e\u53ef\u89c6\u5316\u5c06\u8981\u53d1\u751f\u7684\u64cd\u4f5c\u3002\u5728\u95ee\u9898\u53d1\u751f\u4e4b\u524d\u53d1\u73b0\u6f5c\u5728\u95ee\u9898\uff0c\u8282\u7701\u65f6\u95f4\u548c\u6750\u6599\u3002\\n\\n### \u76f8\u673a\u96c6\u6210\\n\\n\u4f7f\u7528 USB \u6444\u50cf\u5934\u8fdb\u884c\u7cbe\u786e\u7684\u5de5\u4ef6\u5bf9\u9f50\u3001\u5b9a\u4f4d\uff0c\u751a\u81f3\u80cc\u666f\u63cf\u6479\u3002\u975e\u5e38\u9002\u5408\u5728\u73b0\u6709\u6750\u6599\u4e0a\u5b9a\u4f4d\u8bbe\u8ba1\u6216\u5236\u4f5c\u5939\u5177\u3002\\n\\n### \u9ad8\u7ea7\u8def\u5f84\u751f\u6210\\n\\nRayforge \u5305\u62ec\u9ad8\u8d28\u91cf\u56fe\u50cf\u63cf\u6479\u3001\u79fb\u52a8\u65f6\u95f4\u4f18\u5316\u3001\u8def\u5f84\u5e73\u6ed1\u548c\u5149\u6591\u5927\u5c0f\u63d2\u503c\uff0c\u786e\u4fdd\u60a8\u7684\u9879\u76ee\u6309\u8ba1\u5212\u5b8c\u7f8e\u5448\u73b0\u3002\\n\\n## \u5f00\u59cb\u4f7f\u7528\\n\\n\u51c6\u5907\u597d\u5c1d\u8bd5 Rayforge \u4e86\u5417\uff1f\u8bf7\u67e5\u770b\u6211\u4eec\u7684[\u5b89\u88c5\u6307\u5357](/docs/getting-started/installation)\u5f00\u59cb\u4f7f\u7528\u3002\u65e0\u8bba\u60a8\u4f7f\u7528\u7684\u662f Ubuntu\u3001\u901a\u8fc7 Snap \u5b89\u88c5\u7684\u5176\u4ed6 Linux \u53d1\u884c\u7248\uff0c\u8fd8\u662f Windows\uff0c\u6211\u4eec\u90fd\u80fd\u6ee1\u8db3\u60a8\u7684\u9700\u6c42\u3002\\n\\n## \u52a0\u5165\u793e\u533a\\n\\nRayforge \u662f\u5f00\u6e90\u7684\uff0c\u7531\u793e\u533a\u9a71\u52a8\u3002\u6211\u4eec\u6b22\u8fce\u5404\u79cd\u5f62\u5f0f\u7684\u8d21\u732e\uff1a\\n\\n- \u5728 [GitHub Issues](https://github.com/barebaric/rayforge/issues) \u4e0a\u62a5\u544a\u9519\u8bef\u548c\u8bf7\u6c42\u529f\u80fd\\n- \u901a\u8fc7 [pull requests](https://github.com/barebaric/rayforge/pulls) \u8d21\u732e\u4ee3\u7801\\n- \u6539\u8fdb\u6587\u6863\\n- \u5206\u4eab\u60a8\u7684\u9879\u76ee\u548c\u7ecf\u9a8c\\n\\n---\\n\\n*\u6709\u95ee\u9898\u6216\u53cd\u9988\uff1f\u6b22\u8fce\u5728 GitHub \u4e0a\u53c2\u4e0e\u8ba8\u8bba\u6216\u67e5\u770b\u6211\u4eec\u7684[\u6587\u6863](/docs/getting-started/installation)\u3002*"}]}}')}}]);